221	/**
222	 * 起動時に呼ぶ. 既定の 5 分 tick rule を 1 件 seed する.
223	 *
224	 * - 未存在: insert
225	 * - 既存 (system seed): 仕様変更を反映して UPDATE (drift 防止)
226	 * - 既存 (human/ai が触った rule): 何もしない (尊重)
227	 *
228	 * 過去の `default-5sec-tick` (古い 5秒 tick) が残っていれば自動 retire する.
229	 */
230	export function seedDefaultRules(repo: RulesRepo): void {
231	  const existing = repo.find(DEFAULT_TICK_RULE.id);
232	  if (!existing) {
233	    repo.insert({
234	      id: DEFAULT_TICK_RULE.id,
235	      description: DEFAULT_TICK_RULE.description,
236	      trigger_type: DEFAULT_TICK_RULE.trigger_type,
237	      tick_sec: DEFAULT_TICK_RULE.tick_sec,
238	      event_kind: DEFAULT_TICK_RULE.event_kind,
239	      conditions: DEFAULT_TICK_RULE.conditions,
240	      instructions: DEFAULT_TICK_RULE.instructions,
241	      target: DEFAULT_TICK_RULE.target,
242	      cooldown_sec: DEFAULT_TICK_RULE.cooldown_sec,
243	      added_by: "system",
244	    });
245	    repo.log({ rule_id: DEFAULT_TICK_RULE.id, action: "add", actor: "system", detail: "seeded (5min)" });
246	  } else if (
247	    existing.added_by === "system" &&
248	    !existing.removed_at &&
249	    (existing.instructions !== DEFAULT_TICK_RULE.instructions ||
250	      existing.description !== DEFAULT_TICK_RULE.description ||
251	      existing.tick_sec !== DEFAULT_TICK_RULE.tick_sec ||
252	      existing.cooldown_sec !== DEFAULT_TICK_RULE.cooldown_sec ||
253	      existing.conditions !== DEFAULT_TICK_RULE.conditions ||
254	      existing.target !== DEFAULT_TICK_RULE.target)
255	  ) {
256	    const updated = repo.updateSystemDefaults({
257	      id: DEFAULT_TICK_RULE.id,
258	      description: DEFAULT_TICK_RULE.description,
259	      trigger_type: DEFAULT_TICK_RULE.trigger_type,
260	      tick_sec: DEFAULT_TICK_RULE.tick_sec,
261	      event_kind: DEFAULT_TICK_RULE.event_kind,
262	      conditions: DEFAULT_TICK_RULE.conditions,
263	      instructions: DEFAULT_TICK_RULE.instructions,
264	      target: DEFAULT_TICK_RULE.target,
265	      cooldown_sec: DEFAULT_TICK_RULE.cooldown_sec,
266	    });
267	    if (updated) {
268	      repo.log({
269	        rule_id: DEFAULT_TICK_RULE.id,
270	        action: "add",
271	        actor: "system",
272	        detail: "re-seeded (instructions / settings drift detected)",
273	      });
274	    }
275	  }
276	
277	  // 過去の 5sec tick rule を retire
278	  const old = repo.find("default-5sec-tick");
279	  if (old && !old.removed_at) {
280	    repo.remove("default-5sec-tick", "system", "replaced by default-tick (5min interval)");
281	    repo.log({
282	      rule_id: "default-5sec-tick",
283	      action: "remove",
284	      actor: "system",
285	      detail: "replaced by default-tick (5min)",
286	    });
287	  }
288	}
