250	  decrementWsClients(sessionId: string): number {
251	    const now = Math.floor(Date.now() / 1000);
252	    // 二重減算で負数にならないよう CASE で 0 床を保証.
253	    const r = this.db
254	      .prepare(
255	        `UPDATE sessions
256	           SET ws_clients = CASE WHEN ws_clients > 0 THEN ws_clients - 1 ELSE 0 END,
257	               last_seen_at = ?
258	         WHERE id = ?`,
259	      )
260	      .run(now, sessionId);
261	    if (Number(r.changes ?? 0) === 0) return 0;
262	    const row = this.db
263	      .prepare(`SELECT ws_clients FROM sessions WHERE id = ?`)
264	      .get(sessionId) as { ws_clients: number } | undefined;
265	    return row?.ws_clients ?? 0;
266	  }
267	
268	  /** プロセス再起動時に in-memory の WS 接続が消えた状態を反映するため、 全 session の ws_clients を 0 にリセット. */
269	  resetAllWsClients(): number {
270	    const r = this.db
271	      .prepare(`UPDATE sessions SET ws_clients = 0 WHERE ws_clients > 0`)
272	      .run();
273	    return Number(r.changes ?? 0);
274	  }
275	
276	  /** lost で last_seen_at が cutoff より古いものを abandoned 化 */
277	  abandonLost(cutoff: number): number {
278	    const r = this.db
279	      .prepare(
280	        `UPDATE sessions SET status = 'abandoned' WHERE status = 'lost' AND last_seen_at < ?`,
281	      )
282	      .run(cutoff);
283	    return Number(r.changes ?? 0);
284	  }
285	
286	  /** lost / abandoned で last_seen_at が cutoff より古いセッションを完全削除 (events / reports / pending_tasks も) */
287	  purgeStale(cutoff: number): number {
288	    const ids = this.db
289	      .prepare(
290	        `SELECT id FROM sessions WHERE status IN ('lost', 'abandoned') AND last_seen_at < ?`,
291	      )
292	      .all(cutoff) as Array<{ id: string }>;
293	    if (ids.length === 0) return 0;
294	    const idList = ids.map((r) => r.id);
295	    const placeholder = idList.map(() => "?").join(",");
296	    const tx = this.db.transaction((args: string[]) => {
297	      this.db.prepare(`DELETE FROM session_events  WHERE session_id IN (${placeholder})`).run(...args);
298	      this.db.prepare(`DELETE FROM session_reports WHERE session_id IN (${placeholder})`).run(...args);
299	      this.db.prepare(`DELETE FROM pending_tasks   WHERE session_id IN (${placeholder})`).run(...args);
300	      this.db.prepare(`DELETE FROM sessions        WHERE id         IN (${placeholder})`).run(...args);
301	    });
302	    tx(idList);
303	    return idList.length;
304	  }
305	
306	  // ─── session_events ─────────────────────────────────
307	
308	  appendEvent(input: { session_id: string; ts: number; kind: string; payload: object }): void {
309	    this.db
310	      .prepare(
311	        `INSERT INTO session_events(session_id, ts, kind, payload) VALUES (?, ?, ?, ?)`,
312	      )
313	      .run(input.session_id, input.ts, input.kind, JSON.stringify(input.payload));
314	  }
315	
316	  recentEvents(sessionId: string, limit = 100): SessionEventRow[] {
317	    return this.db
318	      .prepare(
319	        `SELECT * FROM session_events WHERE session_id = ? ORDER BY ts DESC LIMIT ?`,
320	      )
321	      .all(sessionId, limit) as SessionEventRow[];
322	  }
323	
324	  /**
325	   * 指定 session の指定 kind の最新 ts を返す. 該当無しは null.
326	   * idle 判定 (kind="prompt" の最終 ts と now の差) に使う.
327	   */
328	  lastEventTsByKind(sessionId: string, kind: string): number | null {
329	    const row = this.db
330	      .prepare(
331	        `SELECT ts FROM session_events
332	         WHERE session_id = ? AND kind = ?
333	         ORDER BY ts DESC LIMIT 1`,
334	      )
335	      .get(sessionId, kind) as { ts: number } | undefined;
336	    return row?.ts ?? null;
337	  }
338	
339	  allEvents(sessionId: string): SessionEventRow[] {
340	    return this.db
341	      .prepare(`SELECT * FROM session_events WHERE session_id = ? ORDER BY ts ASC`)
342	      .all(sessionId) as SessionEventRow[];
343	  }
344	
345	  purgeEventsOlderThan(cutoff: number): number {
346	    const r = this.db
347	      .prepare(`DELETE FROM session_events WHERE ts < ?`)
348	      .run(cutoff);
349	    return Number(r.changes ?? 0);
350	  }
351	
352	  // ─── session_reports ────────────────────────────────
353	
354	  upsertReport(row: SessionReportRow): void {
355	    this.db
356	      .prepare(
357	        `INSERT INTO session_reports(session_id, generated_at, summary_md, bullets, duration_sec, metadata)
358	         VALUES (?, ?, ?, ?, ?, ?)
359	         ON CONFLICT(session_id) DO UPDATE SET
360	           generated_at = excluded.generated_at,
361	           summary_md   = excluded.summary_md,
362	           bullets      = excluded.bullets,
363	           duration_sec = excluded.duration_sec,
364	           metadata     = excluded.metadata`,
365	      )
366	      .run(
367	        row.session_id,
368	        row.generated_at,
369	        row.summary_md,
370	        row.bullets,
371	        row.duration_sec,
372	        row.metadata,
373	      );
374	  }
375	
376	  findReport(sessionId: string): SessionReportRow | null {
377	    return (
378	      (this.db
379	        .prepare(`SELECT * FROM session_reports WHERE session_id = ?`)
380	        .get(sessionId) as SessionReportRow | undefined) ?? null
381	    );
382	  }
383	
384	  listReports(limit = 30): SessionReportRow[] {
385	    return this.db
386	      .prepare(`SELECT * FROM session_reports ORDER BY generated_at DESC LIMIT ?`)
387	      .all(limit) as SessionReportRow[];
388	  }
389	
390	  /** 旧 per-session report は無意味なので truncate. day-report に統合された. */
391	  truncateReports(): number {
392	    const r = this.db.prepare(`DELETE FROM session_reports`).run();
393	    return Number(r.changes ?? 0);
394	  }
395	
396	  /** 単発レポート削除. human 操作用. */
397	  deleteReport(sessionId: string): boolean {
398	    const r = this.db.prepare(`DELETE FROM session_reports WHERE session_id = ?`).run(sessionId);
399	    return Number(r.changes ?? 0) > 0;
400	  }
401	
402	  /** session 全件を削除 (truncate). user 指示で手動 reset 用. events / reports / pending_tasks も連動. */
403	  truncateAllSessions(): number {
404	    const tx = this.db.transaction(() => {
405	      this.db.prepare(`DELETE FROM session_events`).run();
406	      this.db.prepare(`DELETE FROM session_reports`).run();
407	      this.db.prepare(`DELETE FROM pending_tasks`).run();
408	      const r = this.db.prepare(`DELETE FROM sessions`).run();
409	      return Number(r.changes ?? 0);
410	    });
411	    return tx();
412	  }
413	}
