1	/**
2	 * Runtime-toggled admin switches that previously lived as one-shot env
3	 * vars (CONCORDIA_DISABLE_CLAUDE) or were unreachable without a restart.
4	 *
5	 *   - chat_muted               default true   — chitchat / chat-reply / report
6	 *                                                 task enqueues are skipped
7	 *   - rules_enabled            default false  — rule engine + proposer both
8	 *                                                 paused (no claude calls)
9	 *   - rule_proposer_interval   default 3600s  — gap between proposer ticks
10	 *                                                 (60..86400)
11	 *   - workspace_root           default cfg    — ローカルクローン親 (Memoria 解決 /
12	 *                                                 reaction-workflow / Work 走査の基点)
13	 *   - github_org               default cfg    — リポが属する GitHub Organization
14	 *                                                 (PR / repo 操作 owner 解決)
15	 *
16	 * workspace_root / github_org は値が未設定のとき constructor 既定 (config 由来) に
17	 * フォールバックする。 GUI / API から上書きすると schema_meta に永続化され、
18	 * 次回の Discord/Slack bot start (= restart) で実効値として反映される。
19	 *
20	 * Persisted in `schema_meta` (key/value table that already exists). All
21	 * reads cache the row to one SELECT per get — cheap enough for the rule
22	 * engine's per-tick check.
23	 *
24	 * The env var CONCORDIA_DISABLE_CLAUDE=1 still wins as an emergency OFF
25	 * even when rules_enabled=true in DB — see callers.
26	 */
27	
28	import type Database from "better-sqlite3";
29	
30	const KEY_CHAT_MUTED = "admin.chat_muted";
31	const KEY_RULES_ENABLED = "admin.rules_enabled";
32	const KEY_PROPOSER_INTERVAL = "admin.rule_proposer_interval_sec";
33	const KEY_WORKSPACE_ROOT = "admin.workspace_root";
34	const KEY_WORKSPACE_ROOTS = "admin.workspace_roots";
35	const KEY_GITHUB_ORG = "admin.github_org";
36	const KEY_REACTION_WORKFLOW = "admin.reaction_workflow_enabled";
37	const KEY_REACTION_MAPPINGS = "admin.reaction_emoji_overrides";
38	const KEY_LICTOR_MODE = "admin.lictor_mode";
39	const KEY_LICTOR_DEV_PATH = "admin.lictor_dev_path";
40	const KEY_LICTOR_PROD_EXE = "admin.lictor_prod_exe";
41	const KEY_DAILY_TOKEN_BUDGET = "admin.daily_token_budget";
42	
43	/** Lictor 起動モード。 auto = 従来どおり PATH 上の `lictor` を起動。 */
44	export type LictorMode = "auto" | "dev" | "prod";
45	const LICTOR_MODES: readonly LictorMode[] = ["auto", "dev", "prod"];
46	
47	const DEFAULT_CHAT_MUTED = true;
48	const DEFAULT_RULES_ENABLED = false;
49	const DEFAULT_PROPOSER_INTERVAL = 3600;
50	
51	const PROPOSER_INTERVAL_MIN = 60;
52	const PROPOSER_INTERVAL_MAX = 86400;
53	
54	/** workspace_root / github_org / reaction_workflow の未設定時フォールバック (config / env 由来)。 */
55	export interface AdminStateDefaults {
56	  workspaceRoot?: string;
57	  /** 複数ワークスペースルート既定 (config.workspaceRoots 由来)。 先頭がプライマリ。 */
58	  workspaceRoots?: string[];
59	  githubOrg?: string;
60	  /** 既定の reaction-workflow ON/OFF (env CONCORDIA_REACTION_WORKFLOW 由来)。 */
61	  reactionWorkflowEnabled?: boolean;
62	  /** Lictor dev モードのローカルリポ既定パス (例 <workspaceRoot>/Lictor)。 */
63	  lictorDevPath?: string;
64	}
65	
66	export class AdminState {
67	  constructor(
68	    private readonly db: Database.Database,
69	    private readonly defaults: AdminStateDefaults = {},
70	  ) {}
71	
72	  getChatMuted(): boolean {
73	    return this.getBool(KEY_CHAT_MUTED, DEFAULT_CHAT_MUTED);
74	  }
75	
76	  setChatMuted(value: boolean): void {
77	    this.setBool(KEY_CHAT_MUTED, value);
78	  }
79	
80	  getRulesEnabled(): boolean {
81	    return this.getBool(KEY_RULES_ENABLED, DEFAULT_RULES_ENABLED);
82	  }
83	
84	  setRulesEnabled(value: boolean): void {
85	    this.setBool(KEY_RULES_ENABLED, value);
86	  }
87	
88	  getRuleProposerIntervalSec(): number {
89	    const raw = this.getRaw(KEY_PROPOSER_INTERVAL);
90	    if (raw === null) return DEFAULT_PROPOSER_INTERVAL;
91	    const n = Number(raw);
92	    if (!Number.isFinite(n)) return DEFAULT_PROPOSER_INTERVAL;
93	    return clamp(n, PROPOSER_INTERVAL_MIN, PROPOSER_INTERVAL_MAX);
94	  }
95	
96	  setRuleProposerIntervalSec(value: number): void {
97	    if (!Number.isFinite(value)) {
98	      throw new Error("rule_proposer_interval_sec must be a finite number");
99	    }
100	    const clamped = clamp(Math.floor(value), PROPOSER_INTERVAL_MIN, PROPOSER_INTERVAL_MAX);
101	    this.setRaw(KEY_PROPOSER_INTERVAL, String(clamped));
102	  }
103	
104	  /**
105	   * 走査対象のワークスペースルート群 (reaction-workflow / Work 走査の基点)。
106	   * 解決順: array key (新) → 旧 single key (移行用) → config 既定。
107	   * 返り値は trim + 空除去 + 正規化重複除去済。
108	   */
109	  getWorkspaceRoots(): string[] {
110	    const rawArray = this.getRaw(KEY_WORKSPACE_ROOTS);
111	    if (rawArray !== null) {
112	      const parsed = parseRootsJson(rawArray);
113	      const cleaned = cleanRoots(parsed);
114	      if (cleaned.length > 0) return cleaned;
115	    }
116	    // 旧 single key (新 UI で保存する前の DB) からの移行フォールバック。
117	    const single = this.getRaw(KEY_WORKSPACE_ROOT);
118	    if (single !== null && single.trim() !== "") return [single.trim()];
119	    return cleanRoots(this.defaults.workspaceRoots ?? (this.defaults.workspaceRoot ? [this.defaults.workspaceRoot] : []));
120	  }
121	
122	  /** プライマリ (先頭) ルート。 単一ルート前提の消費者 (Lictor 等) 用。 未設定なら ""。 */
123	  getWorkspaceRoot(): string {
124	    return this.getWorkspaceRoots()[0] ?? "";
125	  }
126	
127	  /** 複数ルートを一括設定 (JSON 配列で永続化)。 trim + 空除去 + 重複除去して保存。 */
128	  setWorkspaceRoots(values: string[]): void {
129	    this.setRaw(KEY_WORKSPACE_ROOTS, JSON.stringify(cleanRoots(values)));
130	  }
131	
132	  /** 単一ルート設定 (後方互換)。 array key を [value] で上書きする。 */
133	  setWorkspaceRoot(value: string): void {
134	    this.setWorkspaceRoots(value.trim() ? [value.trim()] : []);
135	  }
136	
137	  /** リポが属する GitHub Organization (例 "LUDIARS")。 未設定なら config 既定。 */
138	  getGithubOrg(): string {
139	    const raw = this.getRaw(KEY_GITHUB_ORG);
140	    if (raw !== null && raw.trim() !== "") return raw;
141	    return this.defaults.githubOrg ?? "";
142	  }
143	
144	  setGithubOrg(value: string): void {
145	    this.setRaw(KEY_GITHUB_ORG, value.trim());
146	  }
147	
148	  /** リアクションワークフローの安全弁 (ON/OFF)。 未設定なら env 由来の constructor 既定。 */
149	  getReactionWorkflowEnabled(): boolean {
150	    return this.getBool(KEY_REACTION_WORKFLOW, this.defaults.reactionWorkflowEnabled ?? false);
151	  }
152	
153	  setReactionWorkflowEnabled(value: boolean): void {
154	    this.setBool(KEY_REACTION_WORKFLOW, value);
155	  }
156	
157	  // ── リアクション 絵文字→アクション 上書き写像 ─────────────────────────
158	  // 既定写像 (reaction-workflow.ts WORKFLOW_EMOJI) に上書きする emoji→action の辞書。
159	  // action 値の妥当性検証は API 層 (isWorkflowAction) で行い、 ここは素の文字列辞書。
160	
161	  /** ユーザ設定の 絵文字→アクション 上書き辞書 (空なら {})。 */
162	  getReactionEmojiOverrides(): Record<string, string> {
163	    const raw = this.getRaw(KEY_REACTION_MAPPINGS);
164	    if (!raw) return {};
165	    try {
166	      const parsed = JSON.parse(raw) as unknown;
167	      if (parsed && typeof parsed === "object" && !Array.isArray(parsed)) {
168	        return parsed as Record<string, string>;
169	      }
170	    } catch {
171	      // 壊れた値は無視 (空辞書扱い)。
172	    }
173	    return {};
174	  }
175	
176	  /** 1 件 upsert (emoji→action)。 */
177	  setReactionEmojiOverride(emoji: string, action: string): void {
178	    const e = emoji.trim();
179	    if (!e) return;
180	    const cur = this.getReactionEmojiOverrides();
181	    cur[e] = action;
182	    this.setRaw(KEY_REACTION_MAPPINGS, JSON.stringify(cur));
183	  }
184	
185	  /** 1 件削除 (既定写像に戻す)。 */
186	  deleteReactionEmojiOverride(emoji: string): void {
187	    const cur = this.getReactionEmojiOverrides();
188	    if (!Object.prototype.hasOwnProperty.call(cur, emoji.trim())) return;
189	    delete cur[emoji.trim()];
190	    this.setRaw(KEY_REACTION_MAPPINGS, JSON.stringify(cur));
191	  }
192	
193	  // ── Lictor 起動設定 (spawn の launcher 解決に使う) ─────────────────────
194	
195	  getLictorMode(): LictorMode {
