    post<{ ok: boolean; status: string; error?: string }>("/v1/admin/discord/start", {}),
  discordBotStop: () =>
    post<{ ok: boolean; status: string; error?: string }>("/v1/admin/discord/stop", {}),
  discordBotRestart: () =>
    post<{ ok: boolean; status: string; error?: string }>("/v1/admin/discord/restart", {}),
